import { defined, pick } from '../../utils/zcutils';
import { getMargin, getTickPadding } from '../../axis/axisutils';
import { mathMax } from '../../core/zc-constants';
import { LOG } from "../../core/scale-type-constant";

/**
 *
 * @param {String} orient
 * @param {Object} tickMargin
 * @param {Object} tickMarkConfig
 * @returns {{x: number, y: number}}
 */

export function _tickPosition(helpers, orient, isInline, isInlineToPlot) {
    let { type, order, config, chart, column } = helpers;
    let ticklabelConfig = config.ticklabel,
        tickMarkConfig = config.tickmark,
        subTickMarkConfig = config.subtickmark,
        margin = getMargin(ticklabelConfig),
        supportSubticks = column.scaleType == LOG;

    var tickMarkSize = pick(tickMarkConfig.size, 6),
        padding = getTickPadding(orient, margin, isInline),
        x = orient === 'left' || orient === 'right' ? 'x' : 'y',
        y = orient === 'left' || orient === 'right' ? 'y' : 'x',
        k = orient === 'top' || orient === 'left' ? -1 : 1,
        k = isInlineToPlot ? -k : k,
        prop = {};

    if (supportSubticks && (subTickMarkConfig.count > 0 || defined(subTickMarkConfig.interval))) {
        tickMarkSize = mathMax(tickMarkSize, pick(subTickMarkConfig.size, 3));
    }

    prop[y] = 0;
    prop[x] = k * (padding + tickMarkSize);

    return prop;
}
